#include <stdio.h>
#include <unistd.h>
#include <signal.h>
#include <sys/wait.h>

void check_status(const char *label, int status) {
    if (WIFEXITED(status))
        printf("%s: exited normally, code=%d\n", label, WEXITSTATUS(status));
    else if (WIFSIGNALED(status))
        printf("%s: killed by signal %d\n", label, WTERMSIG(status));
    else
        printf("%s: other\n", label);
}

int main(void) {
    /* Enfant 1: sortie normale */
    pid_t c1 = fork();
    if (c1 == 0) _exit(0);

    /* Enfant 2: sortie avec code erreur */
    pid_t c2 = fork();
    if (c2 == 0) _exit(42);

    /* Enfant 3: tué par signal */
    pid_t c3 = fork();
    if (c3 == 0) {
        raise(SIGTERM); /* se tue avec SIGTERM */
        _exit(1);    /* jamais atteint */
    }

    int status;
    waitpid(c1, &status, 0);
    check_status("Child 1", status);

    waitpid(c2, &status, 0);
    check_status("Child 2", status);

    waitpid(c3, &status, 0);
    check_status("Child 3", status);

    return 0;
}

